export type TranslationKey = string;

const fallbackLanguage: LanguageCode = 'en';

const languageAliases: Record<string, LanguageCode> = {
  en: 'en',
  'en-us': 'en',
  'en-gb': 'en',
  es: 'es',
  'es-es': 'es',
  'es-mx': 'es',
  fr: 'fr',
  'fr-fr': 'fr',
  'fr-ca': 'fr',
  de: 'de',
  'de-de': 'de',
  pt: 'pt',
  'pt-br': 'pt',
  'pt-pt': 'pt',
  it: 'it',
  'it-it': 'it',
  zh: 'zh',
  'zh-cn': 'zh',
  'zh-hans': 'zh',
  'zh-tw': 'zh',
  'zh-hant': 'zh',
  ja: 'ja',
  'ja-jp': 'ja',
  ko: 'ko',
  'ko-kr': 'ko',
  nl: 'nl',
  'nl-nl': 'nl',
  ru: 'ru',
  'ru-ru': 'ru',
  ar: 'ar',
  'ar-sa': 'ar',
  pl: 'pl',
  'pl-pl': 'pl',
  tr: 'tr',
  'tr-tr': 'tr',
  hi: 'hi',
  'hi-in': 'hi',
};

export function getBrowserLocale(): string {
  if (typeof navigator === 'undefined') return 'en-US';
  return navigator.languages?.[0] || navigator.language || 'en-US';
}

export function detectLanguageCode(locale = getBrowserLocale()): LanguageCode {
  const normalized = locale.replace('_', '-').toLowerCase();
  return languageAliases[normalized] || languageAliases[normalized.split('-')[0] || ''] || fallbackLanguage;
}

export function detectCountry(locale = getBrowserLocale()): string {
  const normalized = locale.replace('_', '-');
  const parts = normalized.split('-');
  const region = parts.find((part) => part.length === 2 || part.length === 3);

  if (!region) {
    const fallbackRegion = detectLanguageCode(locale) === 'es' ? 'ES' : 'US';

    try {
      if (typeof Intl !== 'undefined' && 'DisplayNames' in Intl) {
        const displayNames = new Intl.DisplayNames([detectLanguageCode(locale)], { type: 'region' });
        return displayNames.of(fallbackRegion) || (fallbackRegion === 'ES' ? 'Spain' : 'United States');
      }
    } catch {
      // fall through to the code
    }

    return fallbackRegion === 'ES' ? 'Spain' : 'United States';
  }

  const countryCode = region.toUpperCase();
  try {
    if (typeof Intl !== 'undefined' && 'DisplayNames' in Intl) {
      const displayNames = new Intl.DisplayNames([detectLanguageCode(locale)], { type: 'region' });
      return displayNames.of(countryCode) || countryCode;
    }
  } catch {
    // fall through to the code
  }

  return countryCode;
}

export function detectLocalePreferences(): LocalePreferences {
  const locale = getBrowserLocale();
  return {
    languageCode: detectLanguageCode(locale),
    country: detectCountry(locale),
  };
}

export function getStoredLanguage(value: string | null | undefined): LanguageCode | null {
  if (!value) return null;
  const normalized = value.toLowerCase();
  return (supportedLanguageCodes as readonly string[]).includes(normalized) ? (normalized as LanguageCode) : null;
}

function resolvePath(object: unknown, path: string): unknown {
  return path.split('.').reduce<unknown>((acc, segment) => {
    if (!acc || typeof acc !== 'object') return undefined;
    return (acc as Record<string, unknown>)[segment];
  }, object);
}

export function t(language: LanguageCode, key: string, vars?: Record<string, string | number>): string {
  const tree = translations[language] ?? translations[fallbackLanguage];
  const fallbackTree = translations[fallbackLanguage];
  const template = resolvePath(tree, key) ?? resolvePath(fallbackTree, key) ?? key;

  if (typeof template !== 'string') return key;

  return template.replace(/\{(\w+)\}/g, (_match, token) => {
    const value = vars?.[token];
    return value === undefined || value === null ? '{' + token + '}' : String(value);
  });
}

export function languageFromProfile(languageCode?: string | null): LanguageCode {
  return getStoredLanguage(languageCode) || fallbackLanguage;
}
